// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.model.base.CoreDatatype;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.junit.jupiter.api.Test;

class RdfTermDomainTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void unrestrictedIsKnownAndDistinctFromUnknown() {
		RdfTermDomain literal = RdfTermDomain.classify(VF.createLiteral("value"));

		assertEquals(literal, RdfTermDomain.UNRESTRICTED.meetRequired(literal));
		assertEquals(literal, RdfTermDomain.UNKNOWN.meetRequired(literal));
		assertNotEquals(RdfTermDomain.UNKNOWN.fingerprint(), RdfTermDomain.UNRESTRICTED.fingerprint());
		assertFalse(RdfTermDomain.UNKNOWN.meetRequired(RdfTermDomain.IRI).isEmpty());
		assertFalse(RdfTermDomain.UNRESTRICTED.meetRequired(RdfTermDomain.BNODE).isEmpty());
	}

	@Test
	void observedJoinKeepsResourceKindsRestricted() {
		RdfTermDomain iri = RdfTermDomain.classify(VF.createIRI("http://example.com/value"));
		RdfTermDomain bnode = RdfTermDomain.classify(VF.createBNode());

		RdfTermDomain resource = iri.joinObserved(bnode);

		assertHas(resource, RdfTermDomain.Fact.IRI);
		assertHas(resource, RdfTermDomain.Fact.BNODE);
		assertFalse(resource.has(RdfTermDomain.Fact.LITERAL));
		assertEquals(null, resource.singleValueKind());
	}

	@Test
	void requiredMeetDetectsKindDatatypeTimezoneAndFiniteContradictions() {
		assertTrue(RdfTermDomain.IRI.meetRequired(RdfTermDomain.LITERAL).isEmpty());

		RdfTermDomain intLiteral = RdfTermDomain.classify(VF.createLiteral("7", XSD.INT));
		RdfTermDomain decimalLiteral = RdfTermDomain.classify(VF.createLiteral("7.0", XSD.DECIMAL));
		assertTrue(intLiteral.meetRequired(decimalLiteral).isEmpty());

		RdfTermDomain utcDate = RdfTermDomain.classify(VF.createLiteral("2024-01-01Z", XSD.DATE));
		RdfTermDomain localDate = RdfTermDomain.classify(VF.createLiteral("2024-01-01", XSD.DATE));
		assertTrue(utcDate.meetRequired(localDate).isEmpty());

		RdfTermDomain finite = RdfTermDomain.finiteValues(List.of(VF.createLiteral("7", XSD.INT)));
		assertTrue(finite.meetRequired(RdfTermDomain.IRI).isEmpty());
	}

	@Test
	void finiteMeetKeepsOnlyExactValuesCompatibleWithFacts() {
		var canonical = VF.createLiteral("7", XSD.INT);
		var nonCanonical = VF.createLiteral("007", XSD.INT);
		var iri = VF.createIRI("http://example.com/value");

		RdfTermDomain finite = RdfTermDomain.finiteValues(List.of(canonical, nonCanonical, iri));
		RdfTermDomain canonicalOnly = finite.meetRequired(RdfTermDomain.CANONICAL_INTEGER);

		assertEquals(1, canonicalOnly.finiteValues().size());
		assertTrue(canonicalOnly.finiteValues().contains(canonical));
		assertFalse(canonicalOnly.finiteValues().contains(nonCanonical));
		assertFalse(canonicalOnly.finiteValues().contains(iri));
	}

	@Test
	void observedCanonicalIntegerJoinTracksMinAndMax() {
		RdfTermDomain minusThree = RdfTermDomain.classify(VF.createLiteral("-3", XSD.INT));
		RdfTermDomain eleven = RdfTermDomain.classify(VF.createLiteral("11", XSD.INT));

		RdfTermDomain range = minusThree.joinObserved(eleven);

		assertHas(range, RdfTermDomain.Fact.CANONICAL_INTEGER);
		assertIntegerRange(range, -3, 11);
		assertTrue(range.toString().contains("integerRange=[-3, 11]"));
		assertNotEquals(range.fingerprint(), RdfTermDomain.CANONICAL_INTEGER.fingerprint());
	}

	@Test
	void finiteMeetKeepsOnlyValuesInsideObservedIntegerRange() {
		RdfTermDomain observedRange = RdfTermDomain.classify(VF.createLiteral("50", XSD.INT))
				.joinObserved(RdfTermDomain.classify(VF.createLiteral("60", XSD.INT)));
		var low = VF.createLiteral("49", XSD.INT);
		var min = VF.createLiteral("50", XSD.INT);
		var max = VF.createLiteral("60", XSD.INT);
		var high = VF.createLiteral("61", XSD.INT);

		RdfTermDomain matched = observedRange.meetRequired(RdfTermDomain.finiteValues(List.of(low, min, max, high)));

		assertEquals(2, matched.finiteValues().size());
		assertFalse(matched.finiteValues().contains(low));
		assertTrue(matched.finiteValues().contains(min));
		assertTrue(matched.finiteValues().contains(max));
		assertFalse(matched.finiteValues().contains(high));
		assertIntegerRange(matched, 50, 60);
	}

	@Test
	void fingerprintIncludesFiniteValues() {
		RdfTermDomain intSeven = RdfTermDomain.finiteValues(List.of(VF.createLiteral("7", XSD.INT)));
		RdfTermDomain intEight = RdfTermDomain.finiteValues(List.of(VF.createLiteral("8", XSD.INT)));

		assertNotEquals(intSeven.fingerprint(), intEight.fingerprint());
		assertHasDatatype(intSeven, CoreDatatype.XSD.INT);
	}

	private static void assertHas(RdfTermDomain domain, RdfTermDomain.Fact fact) {
		assertTrue(domain.has(fact), () -> "Expected " + domain + " to contain " + fact);
	}

	private static void assertHasDatatype(RdfTermDomain domain, CoreDatatype.XSD datatype) {
		assertTrue(domain.hasDatatype(datatype), () -> "Expected " + domain + " to contain " + datatype);
	}

	private static void assertIntegerRange(RdfTermDomain domain, long minInclusive, long maxInclusive) {
		assertEquals(new RdfTermDomain.IntegerRange(minInclusive, maxInclusive), domain.integerRange().orElseThrow());
	}
}
